export const REGISTRY_BY_ID: Readonly<Record<string, RefEntry>> = Object.freeze(
  Object.fromEntries(REGISTRY.map(e => [e.id, e]))
);

/** Convenience helper — single homepage URL by id (replaces homepage-urls.ts). */
export function getHomepageUrl(id: string): string | null {
  return REGISTRY_BY_ID[id]?.homepage ?? null;
}
